// Inputs from existing store: symbols (id, name, file, kind, line, is_private), 
// resolved CALL/REF edges (src_sym, dst_sym, kind, resolution_tier), mentioned_idents, chat_files, budget.

1) Build ranking graph (CSR sparse, file- or symbol-level):
   for edge in resolved_edges {                       // call/type/import/override
       let mul = base_for_kind(edge.kind);            // call=1.0, override=0.8, type=0.5, import=0.3
       let mul = mul * mentioned_boost(edge.dst_name) // *10 if in mentioned_idents
                     * longname_boost(edge.dst_name)  // *10 if camel/snake/kebab & len>=8
                     * private_penalty(edge.dst_name); // *0.1 if leading _
       let use_mul = if chat_files.contains(edge.src_file) { mul*50.0 } else { mul };
       let w = use_mul * (edge.num_refs as f64).sqrt() * resolution_factor(edge.tier); //1.0 resolved
       add_edge(src_idx, dst_idx, w);
   }
   // OPTIONAL fenced fallback for dropped/ambiguous idents -> resolution_factor=0.25, never persisted.

2) Personalization vector: p[i] = base; chat files += 100/n; mentioned filenames = max; 
   path-component matches += once. Optionally fold existing betweenness as prior.

3) DETERMINISTIC PageRank (Rust power iteration, NO convergence tolerance):
   const ITERS: u32 = 100; const DAMPING: f64 = 0.85;
   nodes sorted by stable_id; for _ in 0..ITERS { r' = (1-d)*p + d * A^T r (sum in node order); }
   // fixed iters + fixed order => byte-identical across runs on same commit.

4) Apportion file rank -> (definer, ident) by out-edge weight share (aider's formula), 
   sort by rank desc, tie-break on stable symbol id.

5) to_tree budget fit: binary search over top-N tags, render with tree-sitter spans, 
   token_count (reuse CodeGraph's tokenizer), 15% tolerance. Emit coverage footer 
   ('k unresolved calls in shown region') from edge resolution tiers.

CLI: `codegraph repomap [--focus SYMBOL] [--budget N] [--impact]` 
MCP: repo_map tool returning ranked-tag tree + coverage signal.
Wire format: edges read-only; ranking graph is ephemeral in-memory; nothing written back to SQLite.

RUST + TREE-SITTER SKETCH (new crate `codegraph-edit`, CLI `codegraph rename-symbol`/`replace-symbol-body`, gated by a `--write` flag; dry-run/diff is default):

```rust
struct Edit { start: usize, end: usize, new_text: String } // UTF-8 byte offsets

enum RenameOutcome { Refused(Vec<String>), DryRun(Vec<FileDiff>), Applied(Vec<PathBuf>) }

fn rename_symbol(g:&Graph, def_id:&str, new_name:&str, write:bool) -> Result<RenameOutcome> {
  let def = g.node(def_id).ok_or(NotFound)?;
  if !is_safe_class(def) { return Ok(Refused(vec!["not a uniquely-resolved top-level/method/type def".into()])); }
  if !is_valid_identifier(new_name, &def.language) || is_keyword(new_name,&def.language) { return Ok(Refused(..)); }

  // 1. Gather every graph-resolved reference to def (incl. def site), grouped by file+line.
  let refs = g.incoming_refs(def_id); // CALLS + USES edges, carry src_file/src_line
  let mut per_file: BTreeMap<PathBuf, Vec<u32>> = group_by_file(refs, def);

  let mut edits_by_file = BTreeMap::new();
  for (file, lines) in &per_file {
    let src = fs::read(file)?;                       // bytes
    let tree = reparse(file, &src)?;                 // tree-sitter, same grammar as index
    // 2. OCCURRENCE-COMPLETENESS GATE: all identifier tokens == old name in this file
    let occ = identifier_tokens_named(&tree, &src, &def.name); // (byte_start,byte_end,line)
    let expected: HashSet<u32> = lines.iter().copied().collect();
    let mut edits = Vec::new();
    for line_group in occ.group_by_line() {
      if !expected.contains(&line_group.line) {
        return Ok(Refused(vec![format!("{}:{} unaccounted occurrence of '{}' (local/shadow/import?) — refusing", file.display(), line_group.line, def.name)]));
      }
      // 3. same-line disambiguation: must pin exactly one
      match line_group.tokens.as_slice() {
        [t] => edits.push(Edit{start:t.0,end:t.1,new_text:new_name.into()}),
        _   => return Ok(Refused(vec![format!("{}:{} multiple '{}' on one line; only line stored — cannot pin, refusing", file.display(), line_group.line, def.name)])),
      }
    }
    // also assert no expected line lacked an occurrence (graph drift) -> refuse
    edits_by_file.insert(file.clone(), (src, edits));
  }

  // 4. deterministic apply: non-overlap assert, sort, reverse-apply
  let mut diffs = Vec::new();
  for (file,(src,mut edits)) in edits_by_file {
    assert_non_overlapping(&edits)?;                 // else Refused
    edits.sort_by_key(|e| e.start);
    let mut out = src.clone();
    for e in edits.iter().rev() { out.splice(e.start..e.end, e.new_text.bytes()); }
    // 5. post-edit reparse invariant
    if new_error_nodes(&reparse(&file,&out)?, &reparse(&file,&src)?) { return Ok(Refused(vec![format!("{}: edit introduced parse errors — rolled back", file.display())])); }
    diffs.push(make_diff(&file,&src,&out));
    if write { fs::write(&file,&out)?; }
  }
  Ok(if write { Applied(diffs.into_iter().map(|d|d.path).collect()) } else { DryRun(diffs) })
}
```
