#[cfg(feature = "audio")]
pub fn ingest_audio(path: &Path) -> Result<Vec<DocChunk>, String> {
    let pcm = decode_to_16k_mono_f32(path)?;          // symphonia decode + rubato resample (pure-Rust)
    let model = ensure_model("ggml-base.en", BASE_SHA256)?; // fetch+SHA256 verify into cache, deterministic anchor
    let ctx = whisper_rs::WhisperContext::new_with_params(&model, Default::default())
        .map_err(|e| e.to_string())?;
    let mut st = ctx.create_state().map_err(|e| e.to_string())?;
    let mut params = whisper_rs::FullParams::new(SamplingStrategy::Greedy { best_of: 1 }); // temp=0
    params.set_n_threads(1);                            // FP reduction-order determinism
    st.full(params, &pcm).map_err(|e| e.to_string())?;
    // one DocChunk per segment, "[mm:ss] text" so vector search localizes
    let mut out = Vec::new();
    for i in 0..st.full_n_segments().map_err(|e| e.to_string())? {
        let t  = st.full_get_segment_text(i).map_err(|e| e.to_string())?;
        let t0 = st.full_get_segment_t0(i).unwrap_or(0); // centiseconds
        out.push(DocChunk { content_type: "audio".into(), source: path.display().to_string(),
            text: format!("[{:02}:{:02}] {}", t0/6000, (t0/100)%60, t.trim()) });
    }
    Ok(out)
}

#[cfg(feature = "video")]
pub fn ingest_video(path: &Path) -> Result<Vec<DocChunk>, String> {
    let mut chunks = Vec::new();
    for frame_png in extract_keyframes(path)? {         // ffmpeg select='eq(pict_type,I)' or scene>0.4 → temp PNGs
        chunks.extend(ingest_image(&frame_png)?);       // REUSE existing OCR path verbatim
    }
    if let Ok(audio_pcm) = demux_audio_track(path) {    // video also has an audio channel
        chunks.extend(transcribe_pcm(audio_pcm)?);      // shared whisper path with audio arm
    }
    Ok(chunks)
}
